solution_code:
#include <stdio.h>
int popcount_naive(unsigned int n) {
    int count = 0;
    while (n) { count += n & 1; n >>= 1; }
    return count;
}
int popcount_kernighan(unsigned int n) {
    int count = 0;
    while (n) { count++; n &= n - 1; }
    return count;
}

int main(void) {
    {
        printf("%d\n", (int)(popcount_naive(0)));
        printf("%d\n", (int)(popcount_naive(1)));
        printf("%d\n", (int)(popcount_naive(0xFF)));
        printf("%d\n", (int)(popcount_naive(0xDEADBEEF)));
    }
    {
        printf("%d\n", (int)(popcount_kernighan(0)));
        printf("%d\n", (int)(popcount_kernighan(1)));
